sql:
SELECT artist_name 
FROM artists 
WHERE artist_familiarity = (SELECT MAX(artist_familiarity) FROM artists);

SELECT DISTINCT a.artist_name
FROM artists a
JOIN artist_collaborations ac ON a.artist_id = ac.artist1_id OR a.artist_id = ac.artist2_id;

SELECT user_profiles.user_name, user_playlists.playlist_name
FROM user_profiles
INNER JOIN user_playlists ON user_profiles.user_id = user_playlists.user_id;

SELECT artists.artist_name, releases.release_name
FROM artists
INNER JOIN releases ON artists.artist_id = releases.artist_id;

SELECT AVG(play_duration) AS average_play_duration
FROM track_plays
WHERE play_date BETWEEN '2010-01-01' AND '2020-12-31';

SELECT DISTINCT a.artist_name
FROM artists a
JOIN releases r ON a.artist_id = r.artist_id;

SELECT artist_name, artist_familiarity
FROM artists
WHERE artist_familiarity = (SELECT MAX(artist_familiarity) FROM artists);

SELECT a.artist_name, r.release_name
FROM artists a
JOIN releases r ON a.artist_id = r.artist_id;

SELECT COUNT(DISTINCT artist_id) 
FROM artists 
WHERE artist_familiarity > 0.8 AND artist_hotttnesss > 0.9;

external_knowledge:
Solitary stars: Artists not involved in collaborations;
Shimmering albums: Releases with high visual or audio appeal;
Captivated thousands of listeners: High play counts indicating widespread listening;
Earned top accolades: High average ratings indicating high user satisfaction;
Celestial partnership: Dual or multiple artist collaborations.

